let state;
function reset() { state = { round: 1, roster: {}, spin: null, rrTeam: true, rrYear: true, selected: null, moving: null, moveSource: null, filter: "ALL", sort: "gpg", q: "" }; }
const $ = id => document.getElementById(id);
